/**
 * DirectedNewsVideo Composition
 *
 * A multi-scene composition that assembles a news video from a
 * JSON scene plan generated by Claude AI "director".
 *
 * Each scene is rendered as a Remotion <Sequence> with its own
 * duration and transition, creating a dynamic, varied video.
 */
import React from "react";
import {
  AbsoluteFill,
  Audio,
  Sequence,
  useVideoConfig,
  staticFile,
} from "remotion";
import { IntroScene, type IntroSceneProps } from "../components/IntroScene";
import { HeadlineScene, type HeadlineSceneProps } from "../components/HeadlineScene";
import { ContentScene, type ContentSceneProps } from "../components/ContentScene";
import { StatsScene, type StatsSceneProps } from "../components/StatsScene";
import { OutroScene, type OutroSceneProps } from "../components/OutroScene";
import { type SubtitleEntry } from "../components/AnimatedSubtitles";
import { defaultTheme } from "../design-system";

// ── Scene Plan Types ──

interface BaseScene {
  type: string;
  durationSeconds: number;
}

interface IntroScenePlan extends BaseScene {
  type: "intro";
  category: string;
  accentColor?: string;
}

interface HeadlineScenePlan extends BaseScene {
  type: "headline";
  text: string;
  imageSrc?: string;
  accentColor?: string;
}

interface ContentScenePlan extends BaseScene {
  type: "content";
  imageSrc: string;
  keyQuote?: string;
  accentColor?: string;
  voiceoverSrc?: string;
  subtitles?: SubtitleEntry[];
}

interface StatsScenePlan extends BaseScene {
  type: "stats";
  facts: { value: string; label: string }[];
  title?: string;
  accentColor?: string;
}

interface OutroScenePlan extends BaseScene {
  type: "outro";
  message?: string;
  accentColor?: string;
}

export type ScenePlan =
  | IntroScenePlan
  | HeadlineScenePlan
  | ContentScenePlan
  | StatsScenePlan
  | OutroScenePlan;

export interface DirectedNewsVideoProps {
  scenes: ScenePlan[];
  voiceoverSrc: string;
  subtitles: SubtitleEntry[];
  totalDurationSeconds: number;
}

export const DirectedNewsVideo: React.FC<DirectedNewsVideoProps> = ({
  scenes,
  voiceoverSrc,
  subtitles,
}) => {
  const { fps, width, height } = useVideoConfig();
  const isVertical = height > width;

  const resolve = (src: string | undefined) =>
    src ? (src.startsWith("http") ? src : staticFile(src)) : "";

  // Calculate frame offsets for each scene
  let currentFrame = 0;
  const sceneFrames = scenes.map((scene) => {
    const start = currentFrame;
    const duration = Math.ceil(scene.durationSeconds * fps);
    currentFrame += duration;
    return { start, duration };
  });

  // Track time offset for subtitle sync within content scenes
  let subtitleTimeOffset = 0;

  return (
    <AbsoluteFill style={{ backgroundColor: defaultTheme.colors.background }}>
      {/* Render each scene as a Sequence */}
      {scenes.map((scene, i) => {
        const { start, duration } = sceneFrames[i];

        // Calculate subtitle time offset: sum of all scene durations before this one
        const sceneStartSeconds = start / fps;

        let content: React.ReactNode = null;

        switch (scene.type) {
          case "intro":
            content = (
              <IntroScene
                category={scene.category}
                accentColor={scene.accentColor}
              />
            );
            break;

          case "headline":
            content = (
              <HeadlineScene
                text={scene.text}
                imageSrc={scene.imageSrc}
                accentColor={scene.accentColor}
              />
            );
            break;

          case "content":
            content = (
              <ContentScene
                imageSrc={scene.imageSrc}
                voiceoverSrc={scene.voiceoverSrc}
                keyQuote={scene.keyQuote}
                accentColor={scene.accentColor}
                subtitles={scene.subtitles || subtitles.filter(
                  (s) =>
                    s.startTime >= sceneStartSeconds &&
                    s.endTime <= sceneStartSeconds + scene.durationSeconds,
                )}
                subtitleOffset={scene.subtitles ? 0 : sceneStartSeconds}
              />
            );
            break;

          case "stats":
            content = (
              <StatsScene
                facts={scene.facts}
                title={scene.title}
                accentColor={scene.accentColor}
              />
            );
            break;

          case "outro":
            content = (
              <OutroScene
                message={scene.message}
                accentColor={scene.accentColor}
              />
            );
            break;
        }

        return (
          <Sequence key={i} from={start} durationInFrames={duration}>
            {content}
          </Sequence>
        );
      })}

      {/* Global voiceover audio (plays across all scenes) */}
      {voiceoverSrc && (
        <Audio
          src={resolve(voiceoverSrc)}
          volume={defaultTheme.opacity.voiceoverVolume}
        />
      )}

      {/* Watermark */}
      <div
        style={{
          position: "absolute",
          bottom: isVertical ? 80 : 20,
          right: 20,
          opacity: defaultTheme.opacity.watermark,
          fontSize: defaultTheme.typography.watermark.fontSize,
          color: defaultTheme.colors.text,
          fontFamily: defaultTheme.typography.fontFamily.primary,
          fontWeight: defaultTheme.typography.watermark.fontWeight,
          letterSpacing: defaultTheme.typography.watermark.letterSpacing,
        }}
      >
        {defaultTheme.branding.watermarkText}
      </div>
    </AbsoluteFill>
  );
};
